function cua_register_user($username, $password) {
    if (username_exists($username)) {
        return new WP_Error('username_exists', 'Username already exists.');
    }

    $hashed_password = password_hash($password, PASSWORD_DEFAULT);
    $user_id = wp_create_user($username, $hashed_password);

    if (is_wp_error($user_id)) {
        return $user_id;
    }

    return $user_id;
}

function cua_authenticate_user($username, $password) {
    $user = get_user_by('login', $username);

    if (!$user) {
        return new WP_Error('invalid_username', 'Invalid username.');
    }

    if (!password_verify($password, $user->user_pass)) {
        return new WP_Error('incorrect_password', 'Incorrect password.');
    }

    return $user;
}

