    if (isset($_POST['cua_login'])) {
        $username = sanitize_user($_POST['cua_username']);
        $password = $_POST['cua_password'];
        $result = cua_authenticate_user($username, $password);

        if (is_wp_error($result)) {
            echo $result->get_error_message();
        } else {
            echo 'Login successful!';
            wp_set_current_user($result->ID);
            wp_set_auth_cookie($result->ID);
